+func TestResume_WithPriorState(t *testing.T) {
+	t.Parallel()
+
+	workflow := &Workflow{
+		Name: "test-resume",
+		Steps: []Step{
+			{ID: "step1", Prompt: "already done", Agent: "claude"},
+			{ID: "step2", Prompt: "resume here", Agent: "codex", DependsOn: []string{"step1"}},
+		},
+	}
+
+	priorState := &ExecutionState{
+		RunID:      "prior-run-123",
+		WorkflowID: "test-resume",
+		Status:     StatusRunning,
+		StartedAt:  time.Now().Add(-time.Hour),
+		Steps: map[string]StepResult{
+			"step1": {StepID: "step1", Status: StatusCompleted, Output: "done"},
+		},
+		Variables: map[string]interface{}{
+			"myvar": "preserved",
+		},
+	}
+
+	cfg := DefaultExecutorConfig("test")
+	cfg.DryRun = true
+	e := NewExecutor(cfg)
+
+	state, err := e.Resume(context.Background(), workflow, priorState, nil)
+	if err != nil {
+		t.Fatalf("Resume() error = %v", err)
+	}
+	if state.RunID != "prior-run-123" {
+		t.Errorf("RunID = %q, want preserved prior RunID", state.RunID)
+	}
+	if state.Variables["myvar"] != "preserved" {
+		t.Error("Variables should be preserved from prior state")
+	}
+	if state.Status != StatusCompleted {
+		t.Errorf("Status = %v, want completed", state.Status)
+	}
+}
