+func TestResume_FillsDefaults(t *testing.T) {
+	t.Parallel()
+
+	workflow := &Workflow{
+		Name: "fill-defaults",
+		Steps: []Step{
+			{ID: "s1", Prompt: "test", Agent: "claude"},
+		},
+	}
+
+	priorState := &ExecutionState{
+		// Minimal state - all fields empty
+		Steps:     nil,
+		Variables: nil,
+		RunID:     "",
+	}
+
+	cfg := DefaultExecutorConfig("my-session")
+	cfg.DryRun = true
+	cfg.WorkflowFile = "/path/to/workflow.yaml"
+	cfg.RunID = "cfg-run-id"
+	e := NewExecutor(cfg)
+
+	state, err := e.Resume(context.Background(), workflow, priorState, nil)
+	if err != nil {
+		t.Fatalf("Resume() error = %v", err)
+	}
+	if state.Steps == nil {
+		t.Error("Steps should be initialized")
+	}
+	if state.Variables == nil {
+		t.Error("Variables should be initialized")
+	}
+	if state.RunID != "cfg-run-id" {
+		t.Errorf("RunID = %q, want %q (from config)", state.RunID, "cfg-run-id")
+	}
+	if state.Session != "my-session" {
+		t.Errorf("Session = %q, want %q", state.Session, "my-session")
+	}
+	if state.WorkflowFile != "/path/to/workflow.yaml" {
+		t.Errorf("WorkflowFile = %q, want from config", state.WorkflowFile)
+	}
+	if state.WorkflowID != "fill-defaults" {
+		t.Errorf("WorkflowID = %q, want %q", state.WorkflowID, "fill-defaults")
+	}
+}
