+func TestResume_WithDependencyError(t *testing.T) {
+	t.Parallel()
+
+	workflow := &Workflow{
+		Name: "bad-deps",
+		Steps: []Step{
+			{ID: "s1", Prompt: "test", Agent: "claude", DependsOn: []string{"nonexistent"}},
+		},
+	}
+
+	priorState := &ExecutionState{}
+
+	cfg := DefaultExecutorConfig("test")
+	cfg.DryRun = true
+	e := NewExecutor(cfg)
+
+	state, err := e.Resume(context.Background(), workflow, priorState, nil)
+	if err == nil {
+		t.Fatal("Resume() should error on dependency validation failure")
+	}
+	if state.Status != StatusFailed {
+		t.Errorf("Status = %v, want failed", state.Status)
+	}
+	if len(state.Errors) == 0 {
+		t.Error("Errors should contain dependency error")
+	}
+}
